mapper.select:
SELECT MEMBER_SEQ , MEMBER_ID , MEMBER_NAME , BIRTH_YMD , GENDER , PHONE , EMAIL , ROLE_CODE , STATUS , DATE_FORMAT(CREATE_DT, '%Y-%m-%d %H:%i:%s') AS CREATE_DT , DATE_FORMAT(MODIFY_DT, '%Y-%m-%d %H:%i:%s') AS MODIFY_DT FROM MEMBER WHERE 1=1
AND MEMBER_ID LIKE CONCAT('%', #{memberId}, '%')
AND MEMBER_NAME LIKE CONCAT('%', #{memberName}, '%')
AND ROLE_CODE = #{roleCode}
AND STATUS = #{status}
ORDER BY MEMBER_SEQ DESC LIMIT #{safeSize} OFFSET #{offset}

SELECT COUNT(*) FROM MEMBER M WHERE 1 = 1
AND M.MEMBER_ID LIKE CONCAT('%', #{memberId}, '%')
AND M.MEMBER_NAME LIKE CONCAT('%', #{memberName}, '%')
AND M.ROLE_CODE = #{roleCode}
AND M.STATUS = #{status}

SELECT COUNT(1)
FROM MEMBER
WHERE MEMBER_ID = #{memberId}

